SELECT *
FROM iot_alarm
WHERE tenant_id = #{tenantId}
  AND rule_id = #{ruleId}
  AND product_key = #{productKey}
  AND device_key = #{deviceKey}
  AND status = 'ACTIVE'
  AND is_delete = 0
ORDER BY id DESC
LIMIT 1

SELECT * FROM iot_alarm
WHERE is_delete = 0

  AND device_group_key = #{deviceGroupKey}


  AND rule_id = #{ruleId}


  AND severity = #{severity}


  AND status = #{status}

ORDER BY id DESC
LIMIT #{pageSize} OFFSET #{offset}

SELECT COUNT(*) FROM iot_alarm
WHERE is_delete = 0

  AND device_group_key = #{deviceGroupKey}


  AND rule_id = #{ruleId}


  AND severity = #{severity}


  AND status = #{status}
